import React from 'react'
import { Link } from 'react-router-dom'
import Item from './Item'


export default function EditRoom(props) {
  let showItems=()=>{
    return props.room.items.map((i,n) => {
      return ( <Item name={props.i.name} item={i} n={n} turnOnOrOff={props.turnOnOrOff}/>)
  })}
  return (
    <div>
      <h2>Edit the Room</h2>
      <h3>Room-Name: {props.room.name}</h3>
      <h3>Room-Type: {props.room.type}</h3>
      {showItems()}
      <button >Edit room</button>
            <Link to={"/myrooms"}><button>back</button></Link> 


    </div>
  )
}
